<template><div class="grid"><section class="galaxy-card span7"><h3 class="section-title">实时直播面板</h3><el-form label-position="top" class="form-grid"><el-form-item label="直播平台"><el-select v-model="platform" style="width:100%"><el-option label="OBS Studio" value="obs"/><el-option label="抖音直播" value="douyin"/><el-option label="快手直播" value="kuaishou"/></el-select></el-form-item><el-form-item label="OBS WebSocket 地址"><el-input v-model="obsUrl"><template #append><el-button :type="connected?'danger':'primary'" @click="connected=!connected">{{connected?'断开':'连接'}}</el-button></template></el-input></el-form-item><el-form-item label="实时播报文本"><el-input v-model="text" type="textarea" :rows="7" /></el-form-item><div><el-button type="primary" size="large" :loading="loading" @click="speak">实时合成并播放</el-button><el-button @click="text='欢迎进入直播间，今天的福利马上开始。'">重置话术</el-button></div></el-form><audio v-if="audioUrl" :src="audioUrl" controls autoplay style="width:100%;margin-top:18px"></audio></section><section class="galaxy-card span5"><div class="page-title"><h3 class="section-title">脚本切换与直播日志</h3><el-tag :type="connected?'success':'info'">{{connected?'OBS已连接':'未连接'}}</el-tag></div><div v-for="s in scripts" :key="s.id" class="script-card" @click="text=s.content"><b>{{s.title}}</b><p class="muted">{{s.category}} · 点击切换</p></div><div class="console"><p v-for="(l,i) in logs" :key="i">{{l}}</p></div></section></div></template>
<script setup>import { ref,onMounted } from 'vue';import { convertTTS } from '@/api/tts';import { getScriptList } from '@/api/scripts';const obsUrl=ref('ws://localhost:4455'),connected=ref(false),platform=ref('obs'),text=ref('欢迎进入直播间，今天的福利马上开始。'),loading=ref(false),audioUrl=ref(''),scripts=ref([]),logs=ref(['[系统] 银河直播面板已启动']);onMounted(async()=>{scripts.value=await getScriptList()});function mediaUrl(v){if(!v)return'';if(/^(https?:|blob:|data:)/.test(v))return v;return (import.meta.env.VITE_API_BASE||'/api')+(String(v).startsWith('/')?v:'/'+v)}async function speak(){loading.value=true;try{const res=await convertTTS({text_content:text.value,textContent:text.value,platform:platform.value});audioUrl.value=mediaUrl(res.audioUrl||res.audio_url||res.audioOutputPath||res.url);logs.value.unshift(`[TTS] ${new Date().toLocaleTimeString()} 已生成并播放：${text.value.slice(0,24)}...`);if(connected.value)logs.value.unshift('[OBS] 已推送到直播音频源（前端状态）')}finally{loading.value=false}}</script>
